static int parse_request(http_request_t *req, const char *raw_data, size_t data_len) {
    if (!req || !raw_data || data_len == 0) {
        return -1;
    }

    if (data_len >= MAX_REQUEST_SIZE) {
        fprintf(stderr, "ERROR: Request too large (%zu bytes)\n", data_len);
        return -1;
    }

    memcpy(req->raw_request, raw_data, data_len);
    req->raw_request[data_len] = '\0';
    req->raw_length = data_len;

    /* Parse request line */
    char *work_buf = (char *)malloc(data_len + 1);
    if (!work_buf) {
        return -1;
    }
    memcpy(work_buf, raw_data, data_len);
    work_buf[data_len] = '\0';

    /* Find end of request line */
    char *line_end = strstr(work_buf, "\r\n");
    if (!line_end) {
        free(work_buf);
        return -1;
    }
    *line_end = '\0';

    /* Parse method */
    char *token = strtok(work_buf, " ");
    if (!token) {
        free(work_buf);
        return -1;
    }
    req->method = parse_method(token);

    /* Parse path */
    token = strtok(NULL, " ");
    if (!token) {
        free(work_buf);
        return -1;
    }
    strncpy(req->path, token, MAX_PATH_SIZE - 1);
    req->path[MAX_PATH_SIZE - 1] = '\0';

    /* Parse version */
    token = strtok(NULL, " ");
    if (!token) {
        free(work_buf);
        return -1;
    }
    strncpy(req->version, token, sizeof(req->version) - 1);

    free(work_buf);

    /* Parse headers - work with a fresh copy */
    const char *header_start = strstr(raw_data, "\r\n");
    if (header_start) {
        header_start += 2; /* Skip past \r\n */
        req->header_count = 0;

        while (header_start && *header_start != '\0' && req->header_count < MAX_HEADERS) {
            const char *header_end = strstr(header_start, "\r\n");
            if (!header_end || header_end == header_start) {
                break; /* Empty line = end of headers */
            }

            size_t header_len = header_end - header_start;
            char header_line[MAX_HEADER_SIZE];
            if (header_len >= MAX_HEADER_SIZE) {
                header_start = header_end + 2;
                continue;
            }
            memcpy(header_line, header_start, header_len);
            header_line[header_len] = '\0';

            char *colon = strchr(header_line, ':');
            if (colon) {
                *colon = '\0';
                char *value = colon + 1;
                while (*value == ' ') value++;

                strncpy(req->headers[req->header_count].name, header_line, 127);
                req->headers[req->header_count].name[127] = '\0';
                strncpy(req->headers[req->header_count].value, value, 383);
                req->headers[req->header_count].value[383] = '\0';
                req->header_count++;
            }

            header_start = header_end + 2;
        }
    }

    /* Parse body if present */
    const char *body_start = strstr(raw_data, "\r\n\r\n");
    if (body_start) {
        body_start += 4;
        size_t body_len = data_len - (body_start - raw_data);
        if (body_len > 0) {
            req->body = (char *)malloc(body_len + 1);
            if (req->body) {
                memcpy(req->body, body_start, body_len);
                req->body[body_len] = '\0';
                req->body_length = body_len;
            }
        }
    }

    return 0;
}

static const char *get_request_header(const http_request_t *req, const char *name) {
    for (int i = 0; i < req->header_count; i++) {
        if (strcasecmp(req->headers[i].name, name) == 0) {
            return req->headers[i].value;
        }
    }
    return NULL;
}

static void set_response_header(http_response_t *resp, const char *name, const char *value) {
    if (resp->header_count < MAX_HEADERS) {
        strncpy(resp->headers[resp->header_count].name, name, 127);
        resp->headers[resp->header_count].name[127] = '\0';
        strncpy(resp->headers[resp->header_count].value, value, 383);
        resp->headers[resp->header_count].value[383] = '\0';
        resp->header_count++;
    }
}

static void set_response_body(http_response_t *resp, const char *body) {
    if (resp->body) {
        free(resp->body);
    }
    size_t len = strlen(body);
    resp->body = (char *)malloc(len + 1);
    if (resp->body) {
        memcpy(resp->body, body, len + 1);
        resp->body_length = len;
    }
}

static int build_response(http_response_t *resp) {
    if (!resp || !resp->raw_response) return -1;

    int offset = snprintf(resp->raw_response, MAX_RESPONSE_SIZE,
                          "HTTP/1.1 %d %s\r\n",
                          resp->status_code, resp->status_text);

    for (int i = 0; i < resp->header_count && offset < MAX_RESPONSE_SIZE; i++) {
        offset += snprintf(resp->raw_response + offset, MAX_RESPONSE_SIZE - offset,
                           "%s: %s\r\n",
                           resp->headers[i].name, resp->headers[i].value);
    }

    if (resp->body && resp->body_length > 0 && offset < MAX_RESPONSE_SIZE) {
        char len_str[32];
        snprintf(len_str, sizeof(len_str), "%zu", resp->body_length);
        offset += snprintf(resp->raw_response + offset, MAX_RESPONSE_SIZE - offset,
                           "Content-Length: %s\r\n", len_str);
    }

    if (offset < MAX_RESPONSE_SIZE) {
        offset += snprintf(resp->raw_response + offset, MAX_RESPONSE_SIZE - offset, "\r\n");
    }

    if (resp->body && resp->body_length > 0 && offset + resp->body_length < MAX_RESPONSE_SIZE) {
        memcpy(resp->raw_response + offset, resp->body, resp->body_length);
        offset += resp->body_length;
    }

    resp->raw_length = offset;
    return 0;
}

