static void handle_static_file(http_request_t *req, http_response_t *resp) {
    resp->status_code = 200;
    strcpy(resp->status_text, "OK");
    set_response_header(resp, "Server", "EmbeddedHTTP/1.0");
    set_response_header(resp, "Cache-Control", "max-age=3600");

    /* Determine content type from extension */
    const char *ext = strrchr(req->path, '.');
    if (ext) {
        if (strcmp(ext, ".css") == 0) {
            set_response_header(resp, "Content-Type", "text/css");
            set_response_body(resp, "body { font-family: Arial, sans-serif; margin: 20px; }");
        } else if (strcmp(ext, ".js") == 0) {
            set_response_header(resp, "Content-Type", "application/javascript");
            set_response_body(resp, "console.log('Embedded server JS loaded');");
        } else if (strcmp(ext, ".ico") == 0) {
            set_response_header(resp, "Content-Type", "image/x-icon");
            set_response_body(resp, "");
        } else {
            set_response_header(resp, "Content-Type", "application/octet-stream");
            set_response_body(resp, "");
        }
    } else {
        set_response_header(resp, "Content-Type", "text/plain");
        set_response_body(resp, "File not found in static resources");
    }
}

