static int route_request(http_request_t *req, http_response_t *resp) {
    if (!req || !resp) return -1;

    /* Route based on method and path */
    if (req->method == HTTP_GET) {
        if (strcmp(req->path, "/") == 0) {
            handle_get_root(req, resp);
        } else if (strcmp(req->path, "/api/status") == 0) {
            handle_get_status(req, resp);
        } else if (strcmp(req->path, "/api/stats") == 0) {
            handle_get_stats(req, resp);
        } else if (strncmp(req->path, "/static/", 8) == 0 ||
                   strcmp(req->path, "/favicon.ico") == 0) {
            handle_static_file(req, resp);
        } else {
            handle_not_found(req, resp);
            return -1;
        }
    } else if (req->method == HTTP_POST) {
        if (strncmp(req->path, "/api/data", 9) == 0) {
            handle_post_data(req, resp);
        } else {
            handle_not_found(req, resp);
            return -1;
        }
    } else if (req->method == HTTP_PUT) {
        if (strncmp(req->path, "/api/data", 9) == 0) {
            handle_put_data(req, resp);
        } else {
            handle_not_found(req, resp);
            return -1;
        }
    } else if (req->method == HTTP_DELETE) {
        if (strncmp(req->path, "/api/data", 9) == 0) {
            handle_delete_data(req, resp);
        } else {
            handle_not_found(req, resp);
            return -1;
        }
    } else {
        handle_method_not_allowed(req, resp);
        return -1;
    }

    return 0;
}

static int simulate_receive_request(const char **request_data, size_t *data_len) {
    static int request_index = 0;
    static int cycle_count = 0;
    static const int max_cycles = 3;

    if (simulated_requests[request_index] == NULL) {
        request_index = 0;
        cycle_count++;
        if (cycle_count >= max_cycles) {
            return -1; /* Signal to stop the server */
        }
    }

    *request_data = simulated_requests[request_index];
    *data_len = strlen(simulated_requests[request_index]);
    request_index++;

    return 0;
}

static void simulate_send_response(const http_response_t *resp) {
    /* In a real server, this would write to a socket */
    g_stats.bytes_sent += resp->raw_length;
    (void)resp;
}

static double get_time_ms(void) {
    struct timespec ts;
    clock_gettime(CLOCK_MONOTONIC, &ts);
    return ts.tv_sec * 1000.0 + ts.tv_nsec / 1000000.0;
}

int main(void) {
    printf("========================================\n");
    printf("  Embedded HTTP Server Starting\n");
    printf("========================================\n\n");

    bool running = true;

    while (running) {
        const char *raw_data = NULL;
        size_t data_len = 0;

        /* Simulate receiving a request (in real server: accept/read from socket) */
        if (simulate_receive_request(&raw_data, &data_len) != 0) {
            printf("\n--- Server shutting down gracefully ---\n");
            running = false;
            break;
        }

        double start_time = get_time_ms();

        g_stats.total_requests++;
        g_stats.bytes_received += data_len;

        /* Allocate request and response structures */
        http_request_t *request = allocate_request();
        if (!request) {
            fprintf(stderr, "ERROR: Failed to allocate request #%lu\n",
                    g_stats.total_requests);
            g_stats.failed_requests++;
            continue;
        }

        http_response_t *response = allocate_response();
        if (!response) {
            fprintf(stderr, "ERROR: Failed to allocate response #%lu\n",
                    g_stats.total_requests);
            free_request(request);
            g_stats.failed_requests++;
            continue;
        }

        /* Parse the incoming request */
        if (parse_request(request, raw_data, data_len) != 0) {
            fprintf(stderr, "ERROR: Failed to parse request #%lu\n",
                    g_stats.total_requests);
            response->status_code = 400;
            strcpy(response->status_text, "Bad Request");
            set_response_header(response, "Content-Type", "application/json");
            set_response_body(response, "{\"error\":\"bad_request\"}");
            build_response(response);
            simulate_send_response(response);
            free_request(request);
            free_response(response);
            g_stats.failed_requests++;
            continue;
        }

        /* Log the request */
        printf("[Request #%lu] %s %s %s",
               g_stats.total_requests,
               method_to_string(request->method),
               request->path,
               request->version);

        if (request->header_count > 0) {
            const char *host = get_request_header(request, "Host");
            if (host) {
                printf(" (Host: %s)", host);
            }
        }

        if (request->body_length > 0) {
            printf(" [body: %zu bytes]", request->body_length);
        }

        printf("\n");

        /* Route and handle the request */
        int route_result = route_request(request, response);

        /* Add common headers */
        set_response_header(response, "Connection", "keep-alive");

        /* Build the raw response */
        if (build_response(response) != 0) {
            fprintf(stderr, "ERROR: Failed to build response for request #%lu\n",
                    g_stats.total_requests);
            free_request(request);
            free_response(response);
            g_stats.failed_requests++;
            continue;
        }

        /* Send the response */
        simulate_send_response(response);

        double end_time = get_time_ms();
        double elapsed = end_time - start_time;
        g_stats.total_processing_time_ms += elapsed;

        if (route_result == 0) {
            g_stats.successful_requests++;
        } else {
            g_stats.failed_requests++;
        }

        printf("  -> Response: %d %s (%zu bytes, %.3f ms)\n",
               response->status_code,
               response->status_text,
               response->raw_length,
               elapsed);

        /* Free all allocated memory for this request cycle */
        free_request(request);
        request = NULL;

        free_response(response);
        response = NULL;
    }

    /* Print final statistics */
    printf("\n========================================\n");
    printf("  Server Statistics\n");
    printf("========================================\n");
    printf("  Total requests:      %lu\n", g_stats.total_requests);
    printf("  Successful:          %lu\n", g_stats.successful_requests);
    printf("  Failed:              %lu\n", g_stats.failed_requests);
    printf("  Bytes received:      %lu\n", g_stats.bytes_received);
    printf("  Bytes sent:          %lu\n", g_stats.bytes_sent);
    printf("  Total processing:    %.3f ms\n", g_stats.total_processing_time_ms);
    if (g_stats.total_requests > 0) {
        printf("  Avg per request:     %.3f ms\n",
               g_stats.total_processing_time_ms / g_stats.total_requests);
    }
    printf("========================================\n");
    printf("  Server stopped cleanly.\n");
    printf("========================================\n");

    return 0;
}